import{_ as e,o as d,c as o,a4 as a}from"./chunks/framework.CDpUjPX_.js";const m=JSON.parse('{"title":"Design System","description":"","frontmatter":{},"headers":[],"relativePath":"arquitetura/design-system.md","filePath":"arquitetura/design-system.md"}'),r={name:"arquitetura/design-system.md"};function i(s,t,n,c,l,h){return d(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="design-system" tabindex="-1">Design System <a class="header-anchor" href="#design-system" aria-label="Permalink to &quot;Design System&quot;">​</a></h1><p>O Kubex possui dois design systems — um para o dashboard do usuario e outro para o painel admin. Ambos compartilham base escura mas divergem em cor primaria e densidade.</p><p>Arquivos-fonte: <code>.interface-design/system.md</code> dentro de cada frontend.</p><hr><h2 id="visao-geral" tabindex="-1">Visao Geral <a class="header-anchor" href="#visao-geral" aria-label="Permalink to &quot;Visao Geral&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspecto</th><th>Usuario (<code>frontend/</code>)</th><th>Admin (<code>frontend-admin/</code>)</th></tr></thead><tbody><tr><td><strong>Direcao</strong></td><td>Watchtower — vigilante, confiavel</td><td>Mission control — denso, preciso</td></tr><tr><td><strong>Cor primaria</strong></td><td>Emerald-500 (<code>#10b981</code>)</td><td>Indigo-600 via token <code>primary-*</code> (<code>#4f46e5</code>)</td></tr><tr><td><strong>Background</strong></td><td><code>#09090b</code> (zinc-950)</td><td><code>#030712</code> (gray-950)</td></tr><tr><td><strong>Superficie</strong></td><td><code>bg-zinc-900</code> solido</td><td><code>bg-gray-900</code> solido</td></tr><tr><td><strong>Tipografia heading</strong></td><td>Plus Jakarta Sans</td><td>Inter</td></tr><tr><td><strong>Tipografia body</strong></td><td>Inter</td><td>Inter + JetBrains Mono (code)</td></tr></tbody></table><hr><h2 id="paleta-de-cores" tabindex="-1">Paleta de Cores <a class="header-anchor" href="#paleta-de-cores" aria-label="Permalink to &quot;Paleta de Cores&quot;">​</a></h2><h3 id="base" tabindex="-1">Base <a class="header-anchor" href="#base" aria-label="Permalink to &quot;Base&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Contexto</th><th>Background</th><th>Surface</th><th>Border</th></tr></thead><tbody><tr><td>Usuario</td><td><code>#09090b</code> (zinc-950)</td><td><code>#18181b</code> (zinc-900)</td><td><code>border-zinc-800</code></td></tr><tr><td>Admin</td><td><code>#030712</code> (gray-950)</td><td><code>#111827</code> (gray-900)</td><td><code>border-gray-800</code></td></tr></tbody></table><h3 id="primarias" tabindex="-1">Primarias <a class="header-anchor" href="#primarias" aria-label="Permalink to &quot;Primarias&quot;">​</a></h3><p><strong>Usuario:</strong> Emerald + Amber</p><table tabindex="0"><thead><tr><th>Token</th><th>Classe</th><th>Hex</th><th>Uso</th></tr></thead><tbody><tr><td>Primary</td><td><code>bg-emerald-500</code></td><td><code>#10b981</code></td><td>Botoes CTA, indicadores ativos</td></tr><tr><td>Primary hover</td><td><code>bg-emerald-600</code></td><td><code>#059669</code></td><td>Hover de botao</td></tr><tr><td>Primary texto</td><td><code>text-emerald-400</code></td><td><code>#34d399</code></td><td>Links, highlights</td></tr><tr><td>Accent</td><td><code>bg-amber-500</code></td><td><code>#f59e0b</code></td><td>Badge &quot;popular&quot;, alertas</td></tr></tbody></table><p><strong>Admin:</strong> Indigo (via token <code>primary-*</code>)</p><blockquote><p>Nunca usar <code>indigo-*</code> diretamente — sempre <code>primary-*</code> do tailwind config.</p></blockquote><h3 id="status-ambos" tabindex="-1">Status (ambos) <a class="header-anchor" href="#status-ambos" aria-label="Permalink to &quot;Status (ambos)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Status</th><th>Background</th><th>Texto</th></tr></thead><tbody><tr><td>Sucesso</td><td><code>bg-green-900/30</code></td><td><code>text-green-400</code></td></tr><tr><td>Alerta</td><td><code>bg-yellow-900/30</code></td><td><code>text-yellow-400</code></td></tr><tr><td>Erro</td><td><code>bg-red-900/30</code></td><td><code>text-red-400</code></td></tr><tr><td>Info</td><td><code>bg-emerald-900/30</code></td><td><code>text-emerald-400</code></td></tr></tbody></table><hr><h2 id="tipografia" tabindex="-1">Tipografia <a class="header-anchor" href="#tipografia" aria-label="Permalink to &quot;Tipografia&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fonte</th><th>Uso</th><th>Frontends</th></tr></thead><tbody><tr><td>Plus Jakarta Sans (500-800)</td><td>Headings</td><td>Usuario</td></tr><tr><td>Inter (400-700)</td><td>Body, labels, botoes</td><td>Todos</td></tr><tr><td>JetBrains Mono (400-500)</td><td>IDs, hashes, codigo</td><td>Admin</td></tr></tbody></table><h3 id="hierarquia" tabindex="-1">Hierarquia <a class="header-anchor" href="#hierarquia" aria-label="Permalink to &quot;Hierarquia&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Nivel</th><th>Classes</th></tr></thead><tbody><tr><td>Titulo pagina</td><td><code>font-heading text-2xl font-bold text-white</code></td></tr><tr><td>Titulo secao</td><td><code>font-heading text-lg font-semibold text-white</code></td></tr><tr><td>Body</td><td><code>text-sm text-zinc-400</code> (usuario) / <code>text-sm text-gray-400</code> (admin)</td></tr><tr><td>Caption</td><td><code>text-xs text-zinc-500</code></td></tr><tr><td>Mono</td><td><code>font-mono text-xs text-zinc-400</code></td></tr></tbody></table><hr><h2 id="componentes-padrao" tabindex="-1">Componentes Padrao <a class="header-anchor" href="#componentes-padrao" aria-label="Permalink to &quot;Componentes Padrao&quot;">​</a></h2><h3 id="botoes" tabindex="-1">Botoes <a class="header-anchor" href="#botoes" aria-label="Permalink to &quot;Botoes&quot;">​</a></h3><p><strong>Primario (usuario):</strong> <code>rounded-xl bg-gradient-to-r from-emerald-600 to-emerald-500</code> + shadow glow <strong>Primario (admin):</strong> <code>rounded-lg bg-primary-600 px-4 py-2 text-sm font-medium</code><strong>Secundario:</strong> <code>rounded-xl border border-zinc-700 bg-zinc-800</code></p><h3 id="cards" tabindex="-1">Cards <a class="header-anchor" href="#cards" aria-label="Permalink to &quot;Cards&quot;">​</a></h3><p><strong>Usuario:</strong> <code>rounded-xl border border-zinc-800 bg-zinc-900 p-5 hover:border-emerald-500/30</code><strong>Admin:</strong> <code>rounded-xl border border-gray-800 bg-gray-900 p-5</code></p><h3 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h3><p><code>rounded-lg border border-zinc-700 bg-zinc-800 focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500</code></p><h3 id="modais" tabindex="-1">Modais <a class="header-anchor" href="#modais" aria-label="Permalink to &quot;Modais&quot;">​</a></h3><p><strong>Usuario:</strong> <code>rounded-2xl border border-zinc-700 bg-zinc-900 p-6 shadow-2xl</code> + overlay <code>bg-black/60 backdrop-blur-sm</code><strong>Admin:</strong> <code>rounded-xl border border-gray-700 bg-gray-900 shadow-xl</code></p><hr><h2 id="checklist-de-conformidade" tabindex="-1">Checklist de Conformidade <a class="header-anchor" href="#checklist-de-conformidade" aria-label="Permalink to &quot;Checklist de Conformidade&quot;">​</a></h2><ul><li>[ ] Background usa <code>zinc-950</code> (usuario) ou <code>gray-950</code> (admin)</li><li>[ ] Cor primaria e <code>emerald-500</code> (usuario) ou <code>primary-*</code> (admin)</li><li>[ ] Nenhum <code>blue-*</code> como primario no frontend do usuario</li><li>[ ] Headings usam <code>font-heading</code> (Plus Jakarta Sans)</li><li>[ ] Cards sao solidos (<code>bg-zinc-900</code>), nao glassmorphism</li><li>[ ] Botao primario tem gradient emerald + shadow glow</li><li>[ ] Nav sidebar ativo usa <code>emerald-500/10</code> + <code>text-emerald-400</code></li><li>[ ] Badge accent usa <code>amber-500</code></li></ul>',35)])])}const u=e(r,[["render",i]]);export{m as __pageData,u as default};
